                                                    AsyncCallbackInfo *asyncCallbackInfo)
{
    if (globalDataShareHelper != nullptr) {
        SETTING_LOG_INFO("u_c");
        return globalDataShareHelper;
    }
    std::lock_guard<std::mutex> lockGuard(helper);
    if (globalDataShareHelper != nullptr) {
