    std::function<napi_value(napi_env, void *)> finishFunc_ = nullptr;
    std::function<void(void *)> freeFunc_ = nullptr;
    ParamSerializer paramFunc_ = nullptr;
    std::shared_ptr<void> data_ = nullptr;
