// socket相关napi接口
static sio::socket::ptr get_socket(const std::string& classIdStr)
{
    SocketIOClient *client = getClient(classIdStr);
    if (!client) {
        return nullptr;
    }

    if (client->nsp == "") {
        return client->clientInstance.socket();
    } else {
        return client->clientInstance.socket(client->nsp);
    }
}

