}

void AuthSrcConfirmState::GetP2PCredentialInfo(std::shared_ptr<DmAuthContext> context,
    JsonObject &credInfo)
{
    LOGI("start.");
    CHECK_NULL_VOID(context);
    JsonObject queryParams;
    queryParams[FILED_DEVICE_ID_HASH] = context->accessee.deviceIdHash;
