        if (access.isAuthed) {
            continue;
        }
        object[TAG_PROXY_CONTEXT_ID] = app.proxyContextId;
        object[TAG_TOKEN_ID] = access.tokenId;
        if (!context->isServiceBind) {
            object[TAG_BUNDLE_NAME] = access.bundleName;
