typedef struct {
    char brMac[BR_MAC_LEN];
    char uuid[UUID_LEN];
} ProxyBaseInfo;

typedef struct {
    pid_t uid;
    uint32_t cnt;
    ListNode node;
}RetryInfo;

typedef struct {
    ProxyBaseInfo proxyInfo;
    char bundleName[HAP_NAME_MAX_LEN];
    char abilityName[HAP_NAME_MAX_LEN];
    int32_t channelId;
    int32_t appIndex;
    int32_t userId;
    uint32_t requestId;
    pid_t uid;
    pid_t pid;
    bool isEnable;
    bool isConnected;
    bool isVirtualConnect;
    bool isRecovery;
    bool isLastConnect;
