            strcmp(baseInfo->uuid, nodeInfo->proxyInfo.uuid) != 0 ||
            nodeInfo->requestId != requestId || nodeInfo->callingPid != pid) {
            continue;
        }
        (void)SoftBusMutexUnlock(&(g_serverList->lock));
        return true;
    }
    (void)SoftBusMutexUnlock(&(g_serverList->lock));
