    std::string deleteUriStr = CONST_TOOL_DELETE_PHOTO;
    MediaFileUtils::UriAppendKeyValue(deleteUriStr, API_VERSION, to_string(MEDIA_API_VERSION_V10));
    Uri deleteUri(deleteUriStr);
