// 优化版本1：增加提前结束判断
void BubbleSortOptimized(vector<int> &arr)
{
    int n = arr.size();

    for (int i = 0; i < n - 1; i++) {
        bool swapped = false; // 标记本轮是否发生交换

        for (int j = 0; j < n - 1 - i; j++) {
            if (arr[j] > arr[j + 1]) {
                swap(arr[j], arr[j + 1]);
                swapped = true;
            }
        }

        // 如果本轮没有发生交换，说明数组已经有序
        if (!swapped) {
            break; // 提前结束排序
        }
    }
}

