// 鸡尾酒排序（双向冒泡排序）
void CocktailSort(vector<int> &arr)
{
    int n = arr.size();
    int left = 0;
    int right = n - 1;

    while (left < right) {
        bool swapped = false;

        // 从左到右，将最大元素移到右边
        for (int i = left; i < right; i++) {
            if (arr[i] > arr[i + 1]) {
                swap(arr[i], arr[i + 1]);
                swapped = true;
            }
        }
        right--; // 右边界缩小

        // 如果没有发生交换，提前结束
        if (!swapped) {
            break;
        }

        swapped = false;

        // 从右到左，将最小元素移到左边
        for (int i = right; i > left; i--) {
            if (arr[i] < arr[i - 1]) {
                swap(arr[i], arr[i - 1]);
                swapped = true;
            }
        }
        left++; // 左边界缩小

        // 如果没有发生交换，提前结束
        if (!swapped) {
            break;
        }
    }
}

