// 使用二分查找优化插入位置查找
void InsertionSortBinarySearch(vector<int> &arr)
{
    int n = arr.size();

    for (int i = 1; i < n; i++) {
        int key = arr[i];

        // 使用二分查找找到插入位置
        int left = 0;
        int right = i - 1;

        while (left <= right) {
            int mid = left + (right - left) / 2;

            if (arr[mid] > key) {
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }

        // 将元素向后移动
        for (int j = i - 1; j >= left; j--) {
            arr[j + 1] = arr[j];
        }

        // 插入元素
        arr[left] = key;
    }
}

