// 哨兵优化版本
void InsertionSortWithSentinel(vector<int> &arr)
{
    int n = arr.size();
    if (n <= 1) {
        return;
    }

    // 第一步：找到最小元素放在arr[0]作为哨兵
    int minIndex = 0;
    for (int i = 1; i < n; i++) {
        if (arr[i] < arr[minIndex]) {
            minIndex = i;
        }
    }
    swap(arr[0], arr[minIndex]);

    // 现在arr[0]是最小元素，可作为哨兵
    for (int i = 2; i < n; i++) {
        int key = arr[i];
        int j = i - 1;

        // 不需要检查j>=0，因为arr[0]是最小元素
        while (arr[j] > key) {
            arr[j + 1] = arr[j];
            j--;
        }

        arr[j + 1] = key;
    }
}

