// 双向选择排序（鸡尾酒选择排序）
void BidirectionalSelectionSort(vector<int> &arr)
{
    int n = arr.size();
    int left = 0;
    int right = n - 1;

    while (left < right) {
        int minIndex = left;
        int maxIndex = left;

        // 在当前区间中找到最小和最大元素的索引
        for (int i = left + 1; i <= right; i++) {
            if (arr[i] < arr[minIndex]) {
                minIndex = i;
            }
            if (arr[i] > arr[maxIndex]) {
                maxIndex = i;
            }
        }

        // 将最小元素交换到left位置
        if (minIndex != left) {
            swap(arr[left], arr[minIndex]);

            // 如果最大元素原本在left位置，现在被移动到了minIndex位置
            if (maxIndex == left) {
                maxIndex = minIndex;
            }
        }

        // 将最大元素交换到right位置
        if (maxIndex != right) {
            swap(arr[right], arr[maxIndex]);
        }

        left++;
        right--;
    }
}

