        for (int j = i + 1; j < n; j++) {
            if (arr[j] < minValue) {
                minValue = arr[j];
                minIndex = j;
            }
        }

        // 最后进行一次交换
        if (minIndex != i) {
            // 将[i]到[minIndex-1]的元素向后移动
            for (int k = minIndex; k > i; k--) {
                arr[k] = arr[k - 1];
            }
            // 插入最小值
            arr[i] = minValue;
        }
    }
}

