// 获取数字的第d位（从个位开始，d=1表示个位）
int GetDigit(int num, int d)
{
    for (int i = 1; i < d; i++) {
        num /= DECIMAL_BASE;
    }
    return num % DECIMAL_BASE;
}

// 获取数组中最大数字的位数
int GetMaxDigits(const vector<int> &arr)
{
    if (arr.empty()) {
        return 0;
    }

    int maxVal = *max_element(arr.begin(), arr.end());
    int digits = 0;

    while (maxVal > 0) {
        digits++;
        maxVal /= DECIMAL_BASE;
    }

    return max(1, digits); // 至少1位
}

// LSD基数排序 - 十进制
void RadixSortLSD(vector<int> &arr)
{
    if (arr.size() <= 1) {
        return;
    }

    int maxDigits = GetMaxDigits(arr);
    int n = arr.size();

    // 临时数组
    vector<int> output(n);

    // 从个位开始，对每一位进行计数排序
    for (int digit = 1; digit <= maxDigits; digit++) {
        // 计数数组，0-9共10个数字
        vector<int> count(DECIMAL_BASE, 0);

        // 统计每个数字出现的次数
        for (int i = 0; i < n; i++) {
            int d = GetDigit(arr[i], digit);
            count[d]++;
        }

        // 将计数转换为位置索引
        for (int i = 1; i < DECIMAL_BASE; i++) {
            count[i] += count[i - 1];
        }

        // 从后向前遍历，保证稳定性
        for (int i = n - 1; i >= 0; i--) {
            int d = GetDigit(arr[i], digit);
            output[count[d] - 1] = arr[i];
            count[d]--;
        }

        // 复制回原数组
        arr = output;
    }
}

