// MSD基数排序（递归实现）
class MSDRadixSort {
private:
    // 递归排序函数
    void MsdSort(vector<int> &arr, int left, int right, int digit, int maxDigit)
    {
        const int digitCount = 10; // 0-9
        const int numBuckets = 11;
        if (left >= right || digit > maxDigit) {
            return;
        }

        int n = right - left + 1;
        if (n <= SMALL_ARRAY_THRESHOLD) {
            // 小数组使用插入排序
            InsertionSort(arr, left, right);
            return;
        }

        // 计数数组
        vector<int> count(digitCount + 1, 0); // 0-9 + 一个额外位置

        // 临时数组
        vector<int> temp(n);

        // 统计频率（处理digit=0的情况）
        for (int i = left; i <= right; i++) {
            int d = (digit == 0) ? 0 : GetDigit(arr[i], digit);
            count[d + 1]++; // +1为负数预留位置
        }

        // 计算起始位置
        for (int i = 1; i < numBuckets; i++) {
            count[i] += count[i - 1];
        }

        // 排序到临时数组
        for (int i = left; i <= right; i++) {
            int d = (digit == 0) ? 0 : GetDigit(arr[i], digit);
            temp[count[d]++] = arr[i];
        }

        // 复制回原数组
        for (int i = left; i <= right; i++) {
            arr[i] = temp[i - left];
        }

        // 递归排序每个桶
        int start = left;
        for (int i = 0; i < DECIMAL_BASE; i++) {
            int end = left + count[i] - 1;
            if (start <= end) {
                MsdSort(arr, start, end, digit - 1, maxDigit);
                start = end + 1;
            }
        }
    }

    void InsertionSort(vector<int> &arr, int left, int right)
    {
        for (int i = left + 1; i <= right; i++) {
            int key = arr[i];
            int j = i - 1;

            while (j >= left && arr[j] > key) {
                arr[j + 1] = arr[j];
                j--;
            }
            arr[j + 1] = key;
        }
    }

    int GetDigit(int num, int d)
    {
        for (int i = 1; i < d; i++) {
            num /= DECIMAL_BASE;
        }
        return num % DECIMAL_BASE;
    }

    int GetMaxDigits(const vector<int> &arr)
    {
        if (arr.empty()) {
            return 0;
        }

        int maxVal = *max_element(arr.begin(), arr.end());
        int digits = 0;

        while (maxVal > 0) {
            digits++;
            maxVal /= DECIMAL_BASE;
        }

        return max(1, digits);
    }

public:
    void Sort(vector<int> &arr)
    {
        if (arr.size() <= 1) {
            return;
        }

        int maxDigits = GetMaxDigits(arr);
        MsdSort(arr, 0, arr.size() - 1, maxDigits, maxDigits);
    }
};

