class SignedRadixSort {
private:
    // 分离正负数
    void SeparatePosNeg(vector<int> &arr)
    {
        int n = arr.size();
        int left = 0;
        int right = 0;
        right = n - 1;

        while (left <= right) {
            while (left <= right && arr[left] < 0) {
                left++;
            }
            while (left <= right && arr[right] >= 0) {
                right--;
            }

            if (left < right) {
                swap(arr[left], arr[right]);
            }
        }
    }

    // 对绝对值进行基数排序
    void RadixSortAbsolute(vector<int> &arr, int start, int end)
    {
        if (start >= end) {
            return;
        }

        int n = end - start + 1;
        vector<int> output(n);

        // 找到最大绝对值
        int maxAbs = 0;
        for (int i = start; i <= end; i++) {
            int absVal = abs(arr[i]);
            if (absVal > maxAbs) {
                maxAbs = absVal;
            }
        }

        // 计算最大位数
        int maxDigits = 0;
        while (maxAbs > 0) {
            maxDigits++;
            maxAbs /= DECIMAL_BASE;
        }
        maxDigits = max(1, maxDigits);

        // LSD基数排序
        for (int digit = 1; digit <= maxDigits; digit++) {
            vector<int> count(DECIMAL_BASE, 0);

            // 统计频率
            for (int i = start; i <= end; i++) {
                int num = abs(arr[i]);
                int d = GetDigit(num, digit);
                count[d]++;
            }

            // 计算位置
            for (int i = 1; i < DECIMAL_BASE; i++) {
                count[i] += count[i - 1];
            }

            // 从后向前填充
            for (int i = end; i >= start; i--) {
                int num = abs(arr[i]);
                int d = GetDigit(num, digit);
                output[--count[d]] = arr[i];
            }

            // 复制回原数组
            for (int i = start; i <= end; i++) {
                arr[i] = output[i - start];
            }
        }
    }

    int GetDigit(int num, int d)
    {
        for (int i = 1; i < d; i++) {
            num /= DECIMAL_BASE;
        }
        return num % DECIMAL_BASE;
    }

public:
    void Sort(vector<int> &arr)
    {
        if (arr.size() <= 1) {
            return;
        }

        // 分离正负数
        SeparatePosNeg(arr);

        // 找到正负数的分界点
        int negCount = 0;
        for (int num : arr) {
            if (num < 0) {
                negCount++;
            }
        }

        // 对负数部分按绝对值排序（降序，然后反转）
        if (negCount > 0) {
            RadixSortAbsolute(arr, 0, negCount - 1);
            // 反转负数部分
            reverse(arr.begin(), arr.begin() + negCount);
            // 将负数变回负号
            for (int i = 0; i < negCount; i++) {
                arr[i] = -arr[i];
            }
        }

        // 对正数部分排序
        if (negCount < arr.size()) {
            RadixSortAbsolute(arr, negCount, arr.size() - 1);
        }
    }
};

